const required = ['WHATSAPP_PHONE_ID', 'UPI_ID', 'RESTAURANT_NAME', 'MAX_TABLES', 'TAX_RATE', 'TWILIO_ACCOUNT_SID', 'TWILIO_PHONE', 'KITCHEN_PHONE', 'SUPPORT_EMAIL', 'SUPPORT_PHONE'];
const missing = required.filter(v => !$env[v]);
if (missing.length > 0) throw new Error(`Missing env vars: ${missing.join(', ')}`);
const taxRate = parseFloat($env.TAX_RATE);
if (isNaN(taxRate) || taxRate < 0 || taxRate > 100) throw new Error('TAX_RATE must be 0-100');
const maxTables = parseInt($env.MAX_TABLES);
if (isNaN(maxTables) || maxTables < 1) throw new Error('MAX_TABLES must be positive');
const entry = $input.item.json.entry?.[0];
if (!entry?.changes?.[0]?.value) throw new Error('Invalid webhook payload');
return $input.item.json;

const phone = ($input.item.json.from || '').toString();
const phoneRegex = /^[+\d-]+$/;
if (!phoneRegex.test(phone)) return [{json: {...$input.item.json, error: 'INVALID_PHONE', error_msg: 'Invalid phone format'}}];
if (phone.length > 20) return [{json: {...$input.item.json, error: 'PHONE_TOO_LONG', error_msg: 'Phone too long'}}];
const raw = ($input.item.json.raw_text || '').toUpperCase();
const text = raw.replace(/[^A-Z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
const action = ($input.item.json.button_id || $input.item.json.list_id || '').toUpperCase();
return [{json: {...$input.item.json, text, action, timestamp: Date.now()}}];

const items = $input.all();
if (!items || items.length < 2) throw new Error('Missing input data for session processing');
const inputData = items.find(i => i.json.from) || items[0];
const dbResult = items.find(i => i.json.phone) || {};
const phone = inputData.json.from;
const now = Date.now();
let session = {phone, table_number: null, cart: [], customer_name: inputData.json.contact_name, last_seen: now, session_started: now, total_orders: 0, preferences: {}};
if (dbResult.json && dbResult.json.phone) {
  let cart = [];
  let preferences = {};
  try { cart = JSON.parse(dbResult.json.cart || '[]'); if (!Array.isArray(cart)) cart = []; } catch (e) { cart = []; }
  try { preferences = JSON.parse(dbResult.json.preferences || '{}'); if (typeof preferences !== 'object') preferences = {}; } catch (e) { preferences = {}; }
  const lastSeen = new Date(dbResult.json.last_seen).getTime();
  const expired = isNaN(lastSeen) || (now - lastSeen) > 900000;
  if (!expired) {
    session = {...dbResult.json, cart, preferences, last_seen: now};
  } else {
    session.total_orders = dbResult.json.total_orders || 0;
  }
}
return [{json: {...inputData.json, session, is_new_session: !dbResult.json || !dbResult.json.phone}}];

const text = ($input.item.json.text || '').toString();
const tableMatch = text.match(/\d+/);
if (!tableMatch) return [{json: {...$input.item.json, error: 'INVALID_TABLE', error_msg: `❌ Please enter a valid table number (1-${$env.MAX_TABLES})\n\nExample: 'Table 5' or just '5'`}}];
const tableNum = parseInt(tableMatch[0]);
if (isNaN(tableNum)) return [{json: {...$input.item.json, error: 'INVALID_TABLE', error_msg: '❌ Table number must be a valid number'}}];
const maxTables = parseInt($env.MAX_TABLES || '200');
if (tableNum < 1 || tableNum > maxTables) return [{json: {...$input.item.json, error: 'TABLE_OUT_OF_RANGE', error_msg: `❌ Table number must be between 1 and ${maxTables}`}}];
return [{json: {...$input.item.json, table_number: tableNum}}];

const inputData = $input.first().json;
const menuItems = $input.all().slice(1);
if (!menuItems || menuItems.length === 0) return [{json: {...inputData, error: 'NO_MENU', error_msg: '❌ Menu not available'}}];
const categories = {};
menuItems.forEach(item => {
  const cat = item.json.category || 'Other';
  if (!categories[cat]) categories[cat] = [];
  categories[cat].push(item.json);
});
let menuText = '📋 *OUR MENU*\n\n';
Object.keys(categories).sort().forEach(cat => {
  menuText += `━━ ${cat} ━━\n`;
  categories[cat].forEach(item => {
    menuText += `${item.code}: ${item.name} - ₹${item.price}\n`;
  });
  menuText += '\n';
});
menuText += '💡 To order, send item codes\nExample: B10 A5 C3';
return [{json: {...inputData, menu_text: menuText}}];

const text = $input.item.json.text || '';
const itemPattern = /\b([A-Z]+)(\d+)\b/gi;
const matches = [...text.matchAll(itemPattern)];
if (matches.length === 0) return [{json: {...$input.item.json, error: 'NO_ITEMS', error_msg: '❌ No valid item codes found\n\nExample: B10, A5\n\nType MENU to see items'}}];
const parsed_items = matches.map(match => {
  const category = match[1].toUpperCase();
  const number = parseInt(match[2]);
  if (isNaN(number) || number < 1 || number > 9999) throw new Error(`Invalid item: ${match[0]}`);
  return {code: `${category}${number}`, category, number, original: match[0]};
});
const unique = [...new Map(parsed_items.map(i => [i.code, i])).values()];
return [{json: {...$input.item.json, parsed_items: unique}}];

const inputData = $input.first().json;
const foundItems = $input.all().slice(1);
if (!foundItems || foundItems.length === 0) return [{json: {...inputData, error: 'ITEMS_NOT_FOUND', error_msg: '❌ No valid items found\n\nType MENU to see available items'}}];
const session = inputData.session || {};
const cart = session.cart || [];
foundItems.forEach(item => {
  const existing = cart.find(c => c.code === item.json.code);
  if (existing) { existing.quantity += 1; } else {
    cart.push({...item.json, quantity: 1, id: Date.now() + Math.random()});
  }
});
session.cart = cart;
const subtotal = cart.reduce((sum, i) => sum + (i.price * i.quantity), 0);
const taxRate = parseFloat($env.TAX_RATE || '0') / 100;
const tax = Math.round(subtotal * taxRate);
const total = subtotal + tax;
return [{json: {...inputData, session, cart, subtotal, tax, total, items_added: foundItems.map(i => i.json.name)}}];

